// Intersection tiplərinin sintaksisi
interface Person {
  name: string;
}

interface Worker {
  job: string;
}

type Employee = Person & Worker;

let employee: Employee = {
  name: 'Ali',
  job: 'Developer'
};

console.log(employee); // { name: 'Ali', job: 'Developer' }
// let invalid: Employee = { name: 'Vəli' }; // Xəta: job xüsusiyyəti yoxdur

// Intersection vs Union
interface Person {
  name: string;
}

interface Worker {
  job: string;
}

type Employee = Person & Worker;
type Visitor = Person | Worker;

let employee: Employee = { name: 'Ali', job: 'Developer' };
let visitor: Visitor = { name: 'Vəli' }; // Yalnız name kifayətdir

console.log(employee); // { name: 'Ali', job: 'Developer' }
console.log(visitor); // { name: 'Vəli' }

// Obyektlərlə intersection tiplər
interface Contact {
  email: string;
}

interface Profile {
  username: string;
}

type User = Contact & Profile;

let user: User = {
  email: 'ali@example.com',
  username: 'ali123'
};

console.log(user); // { email: 'ali@example.com', username: 'ali123' }
// let invalid: User = { email: 'veli@example.com' }; // Xəta: username yoxdur

// Funksiyalarda intersection tiplər
interface HasId {
  id: number;
}

interface HasName {
  name: string;
}

type IdentifiedPerson = HasId & HasName;

function printDetails(person: IdentifiedPerson): string {
  return `ID: ${person.id}, Name: ${person.name}`;
}

let person: IdentifiedPerson = { id: 1, name: 'Ali' };
console.log(printDetails(person)); // ID: 1, Name: Ali
// let invalid: IdentifiedPerson = { id: 2 }; // Xəta: name yoxdur

// Interfeyslərdə və type aliases ilə intersection
type Address = {
  city: string;
};

interface Details {
  age: number;
}

type Citizen = Address & Details;

let citizen: Citizen = {
  city: 'Baku',
  age: 25
};

console.log(citizen); // { city: 'Baku', age: 25 }
// let invalid: Citizen = { city: 'Istanbul' }; // Xəta: age yoxdur

// Praktik nümunə
interface Product {
  id: number;
  name: string;
}

interface Priced {
  price: number;
}

type PricedProduct = Product & Priced;

function displayProduct(product: PricedProduct): string {
  return `ID: ${product.id}, Name: ${product.name}, Price: ${product.price}`;
}

let product: PricedProduct = {
  id: 1,
  name: 'Laptop',
  price: 1000
};

console.log(displayProduct(product)); // ID: 1, Name: Laptop, Price: 1000

// Təhlükəsizlik nümunəsi
interface User {
  name: string;
}

interface Role {
  role: string;
}

type Admin = User & Role;

function getAdminInfo(admin: Admin): string {
  return `${admin.name} is ${admin.role}`;
}

let admin: Admin = { name: 'Ali', role: 'Administrator' };
console.log(getAdminInfo(admin)); // Ali is Administrator
// let invalid: Admin = { name: 'Vəli' }; // Xəta: role yoxdur

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali' };
console.log(unsafe.name, unsafe.job); // undefined, runtime xətası ola bilər

// Düzgün yol
interface Person {
  name: string;
}

interface Worker {
  job: string;
}

type Employee = Person & Worker;
let employee: Employee = { name: 'Ali', job: 'Developer' };
console.log(employee.name, employee.job); // Ali, Developer

// Real layihə ssenarisi
interface Item {
  id: number;
  name: string;
}

interface Discountable {
  discount: number;
}

type DiscountedItem = Item & Discountable;

function calculateFinalPrice(item: DiscountedItem): number {
  return item.id * item.discount;
}

let item: DiscountedItem = { id: 1, name: 'Phone', discount: 0.9 };
console.log(calculateFinalPrice(item)); // 0.9

