// Пересечение против объединения
interface Person {
  name: string;
}

interface Worker {
  job: string;
}

type Employee = Person & Worker;
type Visitor = Person | Worker;

let employee: Employee = { name: 'Алиса', job: 'Разработчик' };
let visitor: Visitor = { name: 'Боб' }; // Достаточно только name

console.log(employee); // { name: 'Алиса', job: 'Разработчик' }
console.log(visitor); // { name: 'Боб' }

// Типы пересечения с объектами
interface Contact {
  email: string;
}

interface Profile {
  username: string;
}

type User = Contact & Profile;

let user: User = {
  email: 'alice@example.com',
  username: 'alice123'
};

console.log(user); // { email: 'alice@example.com', username: 'alice123' }
// let invalid: User = { email: 'bob@example.com' }; // Ошибка: отсутствует username

// Типы пересечения в функциях
interface HasId {
  id: number;
}

interface HasName {
  name: string;
}

type IdentifiedPerson = HasId & HasName;

function printDetails(person: IdentifiedPerson): string {
  return `ID: ${person.id}, Имя: ${person.name}`;
}

let person: IdentifiedPerson = { id: 1, name: 'Алиса' };
console.log(printDetails(person)); // ID: 1, Имя: Алиса
